import { Link } from "react-router-dom";
import { useSelector } from "react-redux";
import { NavDropdown, Form } from "react-bootstrap";
import { DropdownButton } from "react-bootstrap";

import { useState } from "react";

const NavBar = () => {
  const { cartTotalQuantity } = useSelector((state) => state.cart);
  const [resultsPerPage, setResultsPerPage] = useState();
  const [type, setType] = useState("");
  const [loading, setLoading] = useState(true);

  return (
    <nav className="nav-bar">
      <a href="/home">
        <h2>Online Shoping</h2>
      </a>
      <Form.Select

        aria-label="nav-dropdown-dark-example"
        onChange={(e) => {
          setLoading(true);
          setType(e.target.value);
        }}
        className="primary-inp"
      >
        <option value="people">People</option>
        <option value="planet">Planets</option>
        <option value="starship">Starships</option>
      </Form.Select>
      <NavDropdown
        id="nav-dropdown-dark-example"
        drop="left"
        title="Products"
        menuVariant="dark"

        onChange={(e) => {
          setLoading(true);
          setType(e.target.value);
        }}
      >
        <NavDropdown.Item href="/mobile">Mobile</NavDropdown.Item>
        <NavDropdown.Item href="/tv">TV</NavDropdown.Item>
        <NavDropdown.Item href="/laptop">Laptop</NavDropdown.Item>
        <NavDropdown.Item href="/ac">AC</NavDropdown.Item>
        <NavDropdown.Item href="/watch">Watch</NavDropdown.Item>

        {/* <NavDropdown.Divider /> */}
      </NavDropdown>

      <Link to="/">login</Link>
      <Link to="/regi">Sign Up</Link>

      <Link to="/cart">
        <div className="nav-bag">
          <svg
            xmlns="http://www.w3.org/2000/svg"
            width="35"
            height="35"
            fill="currentColor"
            className="bi bi-handbag-fill"
            viewBox="0 0 16 16"
          >
            <path d="M8 1a2 2 0 0 0-2 2v2H5V3a3 3 0 1 1 6 0v2h-1V3a2 2 0 0 0-2-2zM5 5H3.36a1.5 1.5 0 0 0-1.483 1.277L.85 13.13A2.5 2.5 0 0 0 3.322 16h9.355a2.5 2.5 0 0 0 2.473-2.87l-1.028-6.853A1.5 1.5 0 0 0 12.64 5H11v1.5a.5.5 0 0 1-1 0V5H6v1.5a.5.5 0 0 1-1 0V5z" />
          </svg>

          <span className="bag-quantity">
            <span>{cartTotalQuantity}</span>
          </span>
        </div>
      </Link>
    </nav>
  );
};

export default NavBar;
